import React from "react";
import CardContent from "./CardContent";
import Card from "./Card";

export default function WorksCard() {
  return (
    <Card cardId="works">
      <CardContent title="Proyectos">
        <div className="content relative">
          <div className="works flex flex-wrap">
            <Work
              projectLink="https://github.com/axelestrada/ModernCalculator"
              name="Calculadora para Android"
              category="React Native"
              image="/works/calculator-react-native.jpg"
              imageAlt="Modern Calculator in React Native"
            />

            <Work
              projectLink="https://axelestrada.github.io/mini-ecommerce"
              name="Mini Ecommerce"
              category="Vanilla Javascript | PHP"
              image="/works/mini-ecommerce.jpg"
              imageAlt="Mini Ecommerce Using Vanilla JavaScript y PHP"
            />

            <Work
              projectLink="https://github.com/axelestrada/realtime-chat-app"
              name="Chat en Tiempo Real"
              category="Ionic React | Node JS"
              image="/works/realtime-chat.png"
              imageAlt="Realtime Chat Ionic"
            />

            <Work
              projectLink="https://axelestrada.github.io/mp3-player/"
              name="Reproductor MP3"
              category="Vanilla Javascript"
              image="/works/mp3-player.jpg"
              imageAlt="MP3 Player Using Only HTML, CSS & JavaScript"
            />
            <Work
              projectLink="https://axelestrada.github.io/blog-template/"
              name="Plantilla para Blog"
              category="Vanilla Javascript"
              image="/works/blog-template.jpg"
              imageAlt="Blog Template Using HTML, CSS and JavaScript"
            />
          </div>
        </div>
      </CardContent>
    </Card>
  );
}

function Work({ name, category, image, imageAlt, projectLink }) {
  return (
    <div className="pb-5 sm:pb-0 pt-5 text-center w-full text-usm uppercase text-white85 font-medium">
      <a href={projectLink} target="_blank" rel="noopener noreferrer">
        <div className="image">
          <img className="w-full" loading="lazy" src={image} alt={imageAlt} />
        </div>
        <div className="description pt-3">
          <h4>{name}</h4>
          <h5 className="text-white66 font-light text-uxs">{category}</h5>
        </div>
      </a>
    </div>
  );
}
