import React from 'react';
import CardContent from './CardContent';
import Card from './Card';

import { FontAwesomeIcon } from '@fortawesome/react-fontawesome';
import { faCode, faMobileAlt, faHeadset } from '@fortawesome/free-solid-svg-icons';
import { faSearchengin } from '@fortawesome/free-brands-svg-icons';

export default function ServicesCard() {
	return (
    <Card cardId="services">
      <CardContent title="Servicios">
        <div className="content relative">
          <div className="flex flex-wrap items-start">
            <Service icon={faCode} name="Desarrollo Web">
              Un sitio web refleja la esencia, los valores y la profesionalidad
              de su empresa, haciendo que sus clientes se sientan identificados.
            </Service>

            <Service icon={faSearchengin} name="Optimización de Seo">
              Tienes un sitio web pero no obtienes el número esperado de
              visitantes, optimizamos tu sitio web para que aparezca en los
              primeros resultados de Google.
            </Service>

            <Service icon={faMobileAlt} name="Desarrollo Móvil">
              Atrae la atención de muchos más clientes potenciales con una
              aplicación móvil que refleja su potencial y superioridad sobre la
              competencia.
            </Service>

            <Service icon={faHeadset} name="Atención al Cliente">
              Soporte gratuito a todos nuestros clientes para despejar cada una
              de sus dudas y ser capaces de tomar una mejor decisión sobre lo
              que realmente necesitan.
            </Service>
          </div>
        </div>
      </CardContent>
    </Card>
  );
}

function Service({ children, icon, name }) {
	return (
		<div className="service w-full sm:w-1/2 flex justify-center flex-col pt-5 pb-5 relative">
			<div className="icon w-16 h-16 flex justify-center items-center rounded-full">
				<FontAwesomeIcon className="text-3xl text-greenMain" icon={icon} />
			</div>

			<h4 className="name mt-4 mb-2 font-medium uppercase text-usm text-white85">{name}</h4>

			<p>{children}</p>
		</div>
	);
}
