import React from 'react';

import NavItem from './NavItem';
import { faUser, faTools, faHammer, faSms, faCog } from '@fortawesome/free-solid-svg-icons';

export default function Navbar() {
		return (
		<header className="navbar max-w-2xl md:max-w-lg fixed md:absolute top-0 left-1/2 bg-backgroundMain rounded m-1.5 md:mt-0">
			<nav>
				<ul className="flex justify-evenly items-center">
					<NavItem title="Sobre mi" href="about" icon={faUser} />
					<NavItem title="Servicios" href="services" icon={faCog} />
					<NavItem title="Habilidades" href="skills" icon={faTools} />
					<NavItem title="Proyectos" href="works" icon={faHammer} />
					<NavItem title="Contácteme" href="contact" icon={faSms} />
				</ul>
			</nav>
		</header>
	);
}
