import React from "react";
import CardContent from "./CardContent";
import Card from "./Card";

export default function AboutCard() {
  return (
    <Card cardId="about" otherClasses="active">
      <CardContent title="Sobre Mi">
        <div className="content relative">
          <div className="pt-5 pb-5 font-medium">
            <p>
              Hola, Soy Axel, Desarrollador web principalmente enfocado a dar el
              mejor resultado al cliente dependiendo de sus necesidades. Tengo
              experiencia desarrollando proyectos personales utilizando Vanilla
              Javascript y frameworks como React y NextJs, utilizando como
              backend a Nodejs o PHP, con bases de datos relacionales y no
              relacionales.
              <br />
              <br />
              Actualmente me encuentro desarrollando un Chat en Tiempo real
              utilizando Ionic + React + Nodejs + Mongodb, con el cual eh
              mejorado mis habilidades con Nodejs y Mongodb.
            </p>
            <p className="hidden md:block">
              <br />
              Constantemente estoy aprendiendo nuevas tecnologías que me
              permitan aumentar mi desempeño al desarrollar un proyecto ya sea
              grande o pequeño.
            </p>
            <p className="hidden md:block">
              <br />
              Al conseguir mi primer trabajo como desarrollador, quiero ingresar
              a la universidad para estudiar Ingeniería Informática o Ingeniería
              de Software
            </p>
          </div>

          <div className="info">
            <ul className="flex flex-wrap overflow-hidden">
              <div className="w-full sm:w-1/2">
                <InfoItem title="Edad" value="18" />
                <InfoItem title="Residencia" value="Honduras" />
              </div>

              <div className="w-full sm:w-1/2">
                <InfoItem title="Freelance" value="Disponible" />
                <InfoItem title="Dirección" value="Tegucigalpa, Honduras" />
              </div>
            </ul>
          </div>
        </div>
      </CardContent>
    </Card>
  );
}

function InfoItem({ title, value }) {
  return (
    <li className="font-medium overflow-hidden overflow-ellipsis whitespace-nowrap">
      <span className="font-semibold uppercase text-white85">
        {title + " . . . . "}
      </span>
      {value}
    </li>
  );
}
